issues.suggested_fix:
Add a test case (for both same-file and cross-file branches) where `mockView.dom.isConnected = false`, then verify that `mockView.dispatch` is NOT called and `onNavigate` is NOT called after `flushMacrotasks()`. For example:

```ts
it('does nothing when view is detached (isConnected: false)', async () => {
  mockInvoke.mockResolvedValue(JSON.stringify(sameFileLocation));
  const onNavigate = vi.fn();
  const ext = reifyGotoDefinition(currentUri, onNavigate) as any;
  const mockView = {
    posAtCoords: () => 5,
    state: { doc: { lineAt: () => ({ number: 1, from: 0, to: 10 }), line: () => ({ from: 0 }) } },
    dispatch: vi.fn(),
    dom: { isConnected: false },
  };
  ext.handlers.mousedown({ ctrlKey: true, metaKey: false, clientX: 100, clientY: 50 } as MouseEvent, mockView);
  await flushMacrotasks();
  expect(mockView.dispatch).not.toHaveBeenCalled();
  expect(onNavigate).not.toHaveBeenCalled();
});
```
